body.script:
(async function() {
  try {
    const response = await fetch('https://raw.githubusercontent.com/GrilledCheeseHub/Grilled-Cheese-Hub/2fb7c05ef52c0e5e454eb7c1e804560f6a15c88c/Pixel-WASM_1.12.2.html');
    const html = await response.text();

    // Escape HTML and apply syntax highlighting
    let highlighted = html
      .replace(/&/g, '&')
      .replace(//g, '>')
      .replace(/\n/g, '\n');

    // Simple syntax highlighting
    highlighted = highlighted
      .replace(/(<!DOCTYPE[^&]*>)/g, '$1')
      .replace(/(<\/?\w+)/g, '$1')
      .replace(/(>)/g, '$1')
      .replace(/(\w+)=/g, '$1=')
      .replace(/="([^"]*)"'/g, '="$1"')
      .replace(/"([^&#]*)"/g, '"$1"')
      .replace(/(\/\/.*$)/gm, '$1')
      .replace(/("use strict";)/g, '$1')
      .replace(/(\bvar\b|\bfunction\b|\bconst\b|\blet\b)/g, '$1');

    document.getElementById('content').innerHTML = highlighted;

    // Limit display to first 100 lines for performance
    const lines = document.getElementById('content').innerHTML.split('\n');
    if (lines.length > 100) {
      const truncated = lines.slice(0, 100).join('\n');
      document.getElementById('content').innerHTML = truncated + '\n\n... (file continues, view full file on GitHub)';
    }
  } catch (error) {
    document.getElementById('content').innerHTML = 'Error loading file: ' + error.message + '\n\nView the full file at:\nhttps://github.com/GrilledCheeseHub/Grilled-Cheese-Hub/blob/2fb7c05ef52c0e5e454eb7c1e804560f6a15c88c/Pixel-WASM_1.12.2.html';
  }
})();
